import { useState, useEffect } from 'react';
import BankLogin from './components/BankLogin';
import BankSignup from './components/BankSignup';
import BankDashboard from './components/BankDashboard';
import PaymentConfirm from './components/PaymentConfirm';
import PaymentSuccess from './components/PaymentSuccess';
import './App.css';

function App() {
  const [currentPage, setCurrentPage] = useState('login');
  const [loggedInEmail, setLoggedInEmail] = useState(null);
  const [paymentData, setPaymentData] = useState(null);

  useEffect(() => {
    // Check if redirected from EIMS payment
    const params = new URLSearchParams(window.location.search);
    if (params.get('student_id') && params.get('amount')) {
      // Payment redirect from EIMS - store payment data
      setPaymentData({
        student_id: params.get('student_id'),
        semester: params.get('semester'),
        amount: parseFloat(params.get('amount'))
      });
      // Stay on login page if not logged in
    }

    // Auto redirect to success after payment
    if (window.location.pathname.includes('payment-success')) {
      setCurrentPage('success');
    }
  }, []);

  const handleLoginSuccess = (email) => {
    setLoggedInEmail(email);
    // If payment data exists, go to payment confirm
    if (paymentData) {
      setCurrentPage('confirm');
    } else {
      // Otherwise, go to dashboard
      setCurrentPage('dashboard');
    }
  };

  const handleSignupSuccess = () => {
    setCurrentPage('login');
  };

  const handlePaymentSuccess = () => {
    setCurrentPage('success');
    // Auto redirect after 3 seconds
    setTimeout(() => {
      window.location.href = 'http://localhost:3000/student/payment-success';
    }, 3000);
  };

  const handleLogout = () => {
    setLoggedInEmail(null);
    setCurrentPage('login');
    setPaymentData(null);
  };

  const handleBackToLogin = () => {
    setCurrentPage('login');
    setLoggedInEmail(null);
  };

  return (
    <div className="app">
      {currentPage === 'login' && (
        <BankLogin 
          onLoginSuccess={handleLoginSuccess}
          onSignupClick={() => setCurrentPage('signup')}
        />
      )}
      {currentPage === 'signup' && (
        <BankSignup
          onSignupSuccess={handleSignupSuccess}
          onBackClick={handleBackToLogin}
        />
      )}
      {currentPage === 'dashboard' && (
        <BankDashboard
          accountEmail={loggedInEmail}
          onLogout={handleLogout}
        />
      )}
      {currentPage === 'confirm' && paymentData && (
        <PaymentConfirm
          accountId={loggedInEmail}
          paymentData={paymentData}
          onSuccess={handlePaymentSuccess}
          onBack={() => setCurrentPage('dashboard')}
        />
      )}
      {currentPage === 'success' && <PaymentSuccess />}
    </div>
  );
}

export default App;
